// Canonical tool colour system for all type-tools sites.
// Synced automatically by type-tools/scripts/sync-sites.mjs.
// DO NOT edit this file inside a submodule — edit type-tools/shared/lib/toolColors.ts instead.

/** All tool IDs in canonical order. Append new tools at the end — existing hues stay stable. */
export const TOOL_IDS = [
	'axisRhythm',
	'fitFlush',
	'fitWidth',
	'floodText',
	'glyphShaper',
	'hoverBoldly',
	'magnetType',
	'opszStepper',
	'opticalMargin',
	'ragtooth',
	'speechType',
	'stabilType',
	'steadyGray',
	'textBreath',
	'typsettle',
	'vfClamp',
	'wrapType',
] as const

export type ToolId = typeof TOOL_IDS[number]

/** Golden angle in degrees — distributes hues so each new tool fills the largest remaining gap. */
const GOLDEN_ANGLE = 137.508

function hueForIndex(index: number): number {
	return Math.round((index * GOLDEN_ANGLE) % 360)
}

/** --background hsl value for a given tool ID. */
export function toolBg(toolId: string): string {
	const index = (TOOL_IDS as readonly string[]).indexOf(toolId)
	return `hsl(${index >= 0 ? hueForIndex(index) : 0}, 55%, 9%)`
}

/** --btn-bg hsl value for a given tool ID. */
export function toolBtnBg(toolId: string): string {
	const index = (TOOL_IDS as readonly string[]).indexOf(toolId)
	return `hsl(${index >= 0 ? hueForIndex(index) : 0}, 33%, 17%)`
}

/** --foreground hsl value for a given tool ID — light, legible, hue-tinted to match the background. */
export function toolFg(toolId: string): string {
	const index = (TOOL_IDS as readonly string[]).indexOf(toolId)
	return `hsl(${index >= 0 ? hueForIndex(index) : 0}, 15%, 92%)`
}
